        {type:"mc",q:"Was bedeutet 'zusammen-'?",opts:["colored, colorful","stylistic","(prefix) together","colored, colorful"],ans:"(prefix) together",hint:"بادئة تعني الاشتراك والاجتماع مع الآخرين"}
